def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about airports (or related entities) into a single
    fluent, complex sentence. Unknown predicates fall back to a generic phrasing.
    """
    if not triples:
        return ""

    def _clean(val: str) -> str:
        """Remove surrounding quotes if present."""
        return val.strip('"').strip("'")

    # Helper to build a clause for a single triple
    def _clause(s: str, p: str, o: str) -> str:
        if p == "cityServed":
            return f"{s} serves the city of {o}"
        if p == "location":
            return f"{s} is located in {o}"
        if p == "country":
            return f"{s} is in {o}"
        if p == "isPartOf":
            return f"{s} is part of {o}"
        if p == "elevationAboveTheSeaLevel":
            return f"{s} lies at an elevation of {o} metres above sea level"
        if p == "elevationAboveTheSeaLevelInFeet":
            return f"{s} lies at an elevation of {o} feet above sea level"
        if p == "operatingOrganisation":
            return f"{s} is operated by {o}"
        if p == "runwaySurfaceType":
            return f"{s} has a runway surface of {o}"
        if p.endswith("RunwayLengthFeet"):
            idx = p.split("Runway")[0]
            return f"{s}'s {idx.lower()} runway is {o} feet long"
        if p.endswith("RunwayLengthMetre"):
            idx = p.split("Runway")[0]
            return f"{s}'s {idx.lower()} runway is {o} metres long"
        if p == "runwayName":
            return f"{s}'s runway is named {o}"
        if p == "runwayLength":
            return f"{s}'s runway length is {o}"
        # Fallback for any other predicate
        return f"{s} has {p} {o}"

    # Group triples by their subject to avoid repeating the subject in every clause
    from collections import defaultdict
    subject_groups: dict[str, list[Triple]] = defaultdict(list)
    for t in triples:
        subject_groups[t.subject].append(t)

    # Helper to create a phrase without the subject (used inside a subject clause)
    def _phrase(p: str, o: str) -> str:
        o = _clean(o)
        if p == "cityServed":
            return f"serves the city of {o}"
        if p == "location":
            return f"is located in {o}"
        if p == "country":
            return f"is in {o}"
        if p == "isPartOf":
            return f"is part of {o}"
        if p == "elevationAboveTheSeaLevel":
            return f"lies at an elevation of {o} metres above sea level"
        if p == "elevationAboveTheSeaLevelInFeet":
            return f"lies at an elevation of {o} feet above sea level"
        if p == "operatingOrganisation":
            return f"is operated by {o}"
        if p == "runwaySurfaceType":
            return f"has a runway surface of {o}"
        if p == "runwayName":
            return f"has a runway named {o}"
        if p == "runwayLength":
            return f"has a runway length of {o}"
        if p == "iataLocationIdentifier":
            return f"has IATA code {o}"
        if p == "icaoLocationIdentifier":
            return f"has ICAO code {o}"
        if p == "nativeName":
            return f"is also known as {o}"
        if p.endswith("RunwayLengthFeet"):
            idx = p.split("Runway")[0]
            ord_map = {"1st":"first","2nd":"second","3rd":"third","4th":"fourth","5th":"fifth"}
            ord_word = ord_map.get(idx, idx.lower())
            return f"has {ord_word} runway length of {o} feet"
        if p.endswith("RunwayLengthMetre"):
            idx = p.split("Runway")[0]
            ord_map = {"1st":"first","2nd":"second","3rd":"third","4th":"fourth","5th":"fifth"}
            ord_word = ord_map.get(idx, idx.lower())
            return f"has {ord_word} runway length of {o} metres"
        if p.endswith("RunwayNumber"):
            idx = p.split("Runway")[0]
            ord_map = {"1st":"first","2nd":"second","3rd":"third","4th":"fourth","5th":"fifth"}
            ord_word = ord_map.get(idx, idx.lower())
            return f"has {ord_word} runway number {o}"
        if p.endswith("RunwaySurfaceType"):
            idx = p.split("Runway")[0]
            ord_map = {"1st":"first","2nd":"second","3rd":"third","4th":"fourth","5th":"fifth"}
            ord_word = ord_map.get(idx, idx.lower())
            return f"has {ord_word} runway surface of {o}"
        # Fallback for any other predicate
        return f"has {p} {o}"

    # Build a clause for each subject by joining its phrases
    subject_clauses: list[str] = []
    for subj, tlist in subject_groups.items():
        phrases = [_phrase(t.predicate, t.object) for t in tlist]
        if not phrases:
            continue
        # First phrase keeps the subject at the beginning
        clause = f"{subj} {phrases[0]}"
        if len(phrases) > 1:
            clause += ", " + ", ".join(phrases[1:-1]) + ", and " + phrases[-1] if len(phrases) > 2 else f", and {phrases[1]}"
        subject_clauses.append(clause)

    # Combine all subject clauses into one sentence
    if not subject_clauses:
        return ""
    if len(subject_clauses) == 1:
        sentence = subject_clauses[0] + "."
    else:
        sentence = "; ".join(subject_clauses) + "."

    # Capitalise first character
    return sentence[0].upper() + sentence[1:]

